// Static counter to track the number of keys currently stored
static int stored_keys_count = 0;

/**
 * @brief internal helper function to compute a hash for a string
 * Uses the DJB2 algorithm which is robust for simple string hashing.
 * 
 * @param str Null-terminated string to hash
 * @return unsigned long Computed hash value
 */
static unsigned long compute_hash(const char *str) {
    unsigned long hash = 5381;
    int c;

    while ((c = *str++)) {
        hash = ((hash << 5) + hash) + c; /* hash * 33 + c */
    }

    return hash;
}

unsigned long store_api_key(const char* api_key, const char* user_info) {
    // 1. Validate Inputs
    // Check for NULL pointers to prevent dereferencing errors
    if (api_key == NULL || user_info == NULL) {
        return 0;
    }

    // Check for empty strings as per requirements
    if (strlen(api_key) == 0 || strlen(user_info) == 0) {
        return 0;
    }

    // 2. Check Storage Capacity
    // Calculate max items based on the array size defined in the header
    size_t max_capacity = sizeof(key_store) / sizeof(key_store[0]);

    if (stored_keys_count >= max_capacity) {
        return 0; // Table is full
    }

    // 3. Select the next available slot
    APIKeyInfo *entry = &key_store[stored_keys_count];

    // 4. Securely Copy API Key
    // Use strncpy to prevent buffer overflow if input exceeds buffer size (256).
    // We copy size-1 to ensure space for the null terminator.
    strncpy(entry->key, api_key, sizeof(entry->key) - 1);

    // Explicitly null-terminate the string. strncpy does not guarantee this
    // if the source string length >= n.
    entry->key[sizeof(entry->key) - 1] = '\0';

    // 5. Securely Copy User Info
    // Similar safety mechanism for the user buffer (128 bytes).
    strncpy(entry->user, user_info, sizeof(entry->user) - 1);
    entry->user[sizeof(entry->user) - 1] = '\0';

    // Initialize permissions (defaulting to 0)
    entry->permissions = 0;

    // 6. Compute Hash
    // Calculate the hash based on the safely stored key
